import type { ReactNode } from 'react';
import React from 'react';
import SucceedFilled from '@universe-design/icons-react/SucceedFilled';
import ErrorFilled from '@universe-design/icons-react/ErrorFilled';
import clsx from 'clsx';
import { useCssScope } from '../config-provider/hooks';
import type { ProgressProps } from './shared';
import { ProgressStatusEnum } from './shared';
import { isFunction } from '../util';
export interface StepsProps extends ProgressProps {
  /**
   * 数值
   */
  percent: number;
  format?: (percent: number) => ReactNode;
}
const Steps: React.FC<StepsProps> = (props, refs) => {
  const { percent, format, status } = props;
  const cssScope = useCssScope('progress');
  const [success, exception, normal] = ProgressStatusEnum;

  const renderPercent = () => {
    let progressInfoNode: ReactNode;
    switch (status) {
      case success:
        progressInfoNode = (
          <span className={clsx([cssScope('__icon'), cssScope('__icon--success')])}>
            <SucceedFilled />
          </span>
        );
        break;
      case exception:
        progressInfoNode = (
          <span className={clsx([cssScope('__icon'), cssScope('__icon--error')])}>
            <ErrorFilled />
          </span>
        );
        break;
      case normal:
        if (isFunction(format)) {
          progressInfoNode = format(percent);
        } else {
          progressInfoNode = `${percent}%`;
        }
      default:
        break;
    }

    return progressInfoNode;
  };

  return <>{renderPercent()}</>;
};

export default Steps;
